function rewrite(another){
  const text=$('#sourceText').value.trim();if(!text){toast(t('needText'));return}
  if(another)state.variant++;
  const sender=getPersona($('#senderSelect').value),recipient=getPersona($('#recipientSelect').value);
  const target=blendProfiles(sender,recipient,state.adaptation),rank=dominant(target);
  const lang=$('#replyLanguage').value==='auto'?(detectLanguage(text)||recipient.language||'en'):$('#replyLanguage').value;
  const topic=detectTopic(text),intent=detectIntent(text,topic),sensitive=isSensitive(text,topic);
  const output=composeProfileAwareReply(target,rank,lang,topic,$('#toneSelect').value,$('#lengthSelect').value,state.inputMode,intent,text);
  const meetingSuggestion=I18N[lang]?.meetingSuggestion||I18N.en.meetingSuggestion;
  state.lastResult={output,target,lang,topic,intent,sensitive,meetingSuggestion};
  $('#resultText').value=output;$('#emptyResult').classList.add('hidden');$('#resultContent').classList.remove('hidden');
  $('#styleSummary').innerHTML=`<span>◎</span><div><strong>${escapeHtml(t('styleApplied'))}</strong><p>${escapeHtml(profileRationale(target,rank,lang))}</p>${recipeHtml(target,rank)}</div>`;
  renderAdvice(target,rank,text,lang);
  $('#meetingCard').classList.toggle('hidden',!sensitive);$('#otherwiseLabel').classList.toggle('hidden',!sensitive);$('#meetingReason').textContent=t('meetingReason');
  $('#resultMeta').textContent=`${t('localEngine')} · ${t('profileMix')}: ${rank.slice(0,2).map(k=>ENERGY[k].label).join(' + ')} · ${output.length} characters`;
  $('#resultContent').scrollIntoView({behavior:'smooth',block:'nearest'});
}

function composeProfileAwareReply(target,rank,lang,topic,tone,length,inputMode,intent,source){
  const lines=PROFILE_LINES[lang]||PROFILE_LINES.en;
  let count=length==='brief'?2:((target[rank[0]]<36||Math.abs(target[rank[0]]-target[rank[1]])<7)?3:2);
  let selected=rank.filter(k=>target[k]>=16).slice(0,count);
  if(tone==='direct'&&!selected.includes('fiery_red'))selected=[selected[0],'fiery_red',...selected.slice(1)].slice(0,count);
  if(tone==='softer'&&!selected.includes('earth_green'))selected=[selected[0],'earth_green',...selected.slice(1)].slice(0,count);
  const used=new Set();
  let parts=selected.map(k=>lines[k]?.[topic]||lines[k]?.generic).filter(Boolean).filter(line=>{const key=line.toLowerCase();if(used.has(key))return false;used.add(key);return true});
  if(inputMode==='incoming'&&topic==='generic'){
    const incoming={en:'Thanks for the message.',nl:'Dank voor je bericht.',fr:'Merci pour votre message.',de:'Danke für Ihre Nachricht.'};
    parts.unshift(incoming[lang]||incoming.en);
  }
  if($('#questionFlip').checked&&topic==='documents'&&/when|wanneer|quand|wann/i.test(source)){
    const question=lines.cool_blue.documents;
    parts=[question,...parts.filter(p=>p!==question)];
  }
  if(length==='detailed')parts.push(DETAIL_CLOSE[lang]||DETAIL_CLOSE.en);
  let output=parts.join(' ').replace(/\s+/g,' ').trim();
  if(length==='brief')output=shorten(output,lang);
  return output;
}

function profileRationale(target,rank,lang){
  const c=RESULT_COPY[lang]||RESULT_COPY.en;
  const needKey={cool_blue:'blueNeed',fiery_red:'redNeed',sunshine_yellow:'yellowNeed',earth_green:'greenNeed'};
  return `${c.dominant}: ${ENERGY[rank[0]].label} (${Math.round(target[rank[0]])}%) — ${c[needKey[rank[0]]]}. ${c.secondary}: ${ENERGY[rank[1]].label} (${Math.round(target[rank[1]])}%) — ${c[needKey[rank[1]]]}.`;
}

function recipeHtml(target,rank){
  return `<div class="message-recipe">${rank.map(k=>`<span class="recipe-chip ${ENERGY[k].css}"><i></i>${escapeHtml(ENERGY[k].label)} ${Math.round(target[k])}%</span>`).join('')}</div>`;
}

function renderAdvice(target,rank,source,lang){
  const c=RESULT_COPY[lang]||RESULT_COPY.en,hasLink=/(https?:\/\/|www\.|\[[^\]]*link[^\]]*\])/i.test(source);
  const relevant=rank.filter((k,i)=>i<2||target[k]>=23).slice(0,4),items=[];
  for(const k of relevant){
    if(k==='cool_blue'){
      items.push({energy:k,text:hasLink?c.blueUrlPresent:c.blueUrl});
      if(target[k]>=30)items.push({energy:k,text:c.blueFacts});
    }
    if(k==='fiery_red')items.push({energy:k,text:c.red});
    if(k==='sunshine_yellow')items.push({energy:k,text:c.yellow});
    if(k==='earth_green')items.push({energy:k,text:c.green});
  }
  const unique=items.filter((item,i,a)=>a.findIndex(x=>x.text===item.text)===i).slice(0,5);
  $('#adviceTitle').textContent=c.title;$('#adviceIntro').textContent=c.intro;
  $('#adviceList').innerHTML=unique.map(item=>`<li data-energy="${item.energy}">${escapeHtml(item.text)}</li>`).join('');
  $('#adviceCard').classList.toggle('hidden',!unique.length);
}

function shorten(s,lang){
  const sentences=s.match(/[^.!?]+[.!?]?/g)||[s];return sentences.slice(0,2).join('').trim();
}
function styleDescription(target,rank,lang){
  const text={en:{blue:'precise and structured',red:'brief and action-oriented',yellow:'warm and engaging',green:'calm and considerate',bridge:'with a professional bridge'},nl:{blue:'precies en gestructureerd',red:'kort en actiegericht',yellow:'warm en betrokken',green:'rustig en consideraat',bridge:'met een professionele brug'},fr:{blue:'précis et structuré',red:'bref et orienté action',yellow:'chaleureux et engageant',green:'calme et attentionné',bridge:'avec un pont professionnel'},de:{blue:'präzise und strukturiert',red:'kurz und handlungsorientiert',yellow:'warm und einladend',green:'ruhig und rücksichtsvoll',bridge:'mit einer professionellen Brücke'}}[lang]||{};
  return `${text[ENERGY[rank[0]].css]} + ${text[ENERGY[rank[1]].css]}, ${text.bridge}.`;
}

function clearRewrite(){
  $('#sourceText').value='';$('#sourceText').dispatchEvent(new Event('input'));removeImage();$('#resultContent').classList.add('hidden');$('#emptyResult').classList.remove('hidden');$('#adviceCard').classList.add('hidden');state.lastResult=null;state.variant=0;
}
function handleImage(e){const f=e.target.files?.[0];if(!f)return;if(f.size>7*1024*1024){toast(t('screenshotLarge'));e.target.value='';return}const r=new FileReader();r.onload=()=>{$('#preview').src=r.result;$('#preview').classList.remove('hidden');$('#removeImageBtn').classList.remove('hidden');$('#screenshotNote').classList.remove('hidden')};r.readAsDataURL(f)}
function removeImage(){$('#imageInput').value='';$('#preview').src='';$('#preview').classList.add('hidden');$('#removeImageBtn').classList.add('hidden');$('#screenshotNote').classList.add('hidden')}

const COACH={
  capacity:{keywords:/capacity|capaciteit|capacité|kapazität|deadline|project|workload|werklast|charge|arbeitslast|resources/i,contact:'Project sponsor or PMO',route:'Review scope, priorities, capacity and deadline with the project owner before requesting extra resources.'},
  conflict:{keywords:/conflict|samenwerking|collaboration|zusammenarbeit|manager|colleague|collega|collègue/i,contact:'Line manager or confidential contact',route:'Start with a factual overview of what happened and the outcome you need. For a sensitive relationship issue, choose a private conversation.'},
  privacy:{keywords:/privacy|security|beveilig|sécurité|datenschutz|gdpr|rgpd|data/i,contact:'Privacy or Information Security team',route:'Share only the minimum context required and avoid sending sensitive data through an open channel.'},
  wellbeing:{keywords:/struggl|overwhelm|burnout|stress|vertrouw|confidential|confidentiel|vertraulich|talk to someone|praten/i,contact:'Confidential contact or external prevention service',route:'Choose the contact you trust. The request should be voluntary and contain only what you want to share.'},
  it:{keywords:/password|login|computer|software|teams|outlook|system|it issue/i,contact:'IT Service Desk',route:'Include the affected system, impact and any error message, but never share a password.'},
  hr:{keywords:/leave|vacation|contract|salary|hr|verlof|loon|salaire|urlaub|gehalt/i,contact:'People / HR team',route:'Use the HR service channel for policy or employment questions. A personal case may be better handled privately.'}
};
function loadCoachPrompt(key){const text={capacity:{en:'My project needs more time or capacity. Who should I contact?',nl:'Mijn project heeft meer tijd of capaciteit nodig. Met wie bespreek ik dit?',fr:'Mon projet a besoin de plus de temps ou de capacité. Qui dois-je contacter ?',de:'Mein Projekt braucht mehr Zeit oder Kapazität. Wen sollte ich ansprechen?'},conflict:{en:'A collaboration is becoming difficult. Who can help me discuss this constructively?',nl:'Een samenwerking wordt moeilijk. Wie kan mij helpen dit constructief te bespreken?',fr:'Une collaboration devient difficile. Qui peut m’aider à en parler de manière constructive ?',de:'Eine Zusammenarbeit wird schwierig. Wer kann mir helfen, das konstruktiv zu besprechen?'},privacy:{en:'I have a privacy or security question. Who is the right contact?',nl:'Ik heb een privacy- of beveiligingsvraag. Wie is het juiste contact?',fr:'J’ai une question de confidentialité ou de sécurité. Qui est le bon contact ?',de:'Ich habe eine Datenschutz- oder Sicherheitsfrage. Wer ist der richtige Kontakt?'},wellbeing:{en:'I would like to talk to someone confidentially. What are my options?',nl:'Ik wil graag vertrouwelijk met iemand praten. Welke opties zijn er?',fr:'Je souhaite parler confidentiellement à quelqu’un. Quelles sont mes options ?',de:'Ich möchte vertraulich mit jemandem sprechen. Welche Möglichkeiten gibt es?'}};
  $('#coachText').value=text[key]?.[state.lang]||text[key]?.en||'';runCoach();
}
function runCoach(){const text=$('#coachText').value.trim();if(!text){toast(t('coachNeed'));return}const match=Object.entries(COACH).find(([,v])=>v.keywords.test(text))?.[1]||{contact:'Line manager or internal service desk',route:'Clarify the question, expected outcome and urgency, then choose the service with the relevant responsibility.'};const translated=translateCoach(match,state.lang);$('#coachResult').innerHTML=`<h3>${escapeHtml(translated.title)}</h3><p>${escapeHtml(translated.route)}</p><div class="contact-card"><div><strong>${escapeHtml(translated.contact)}</strong><small>${escapeHtml(translated.note)}</small></div><span>${escapeHtml(translated.action)}</span></div>`;$('#coachResult').classList.remove('hidden')}
function translateCoach(match,lang){
  if(lang==='nl')return{title:'Liv stelt deze route voor',contact:coachContactNl(match.contact),route:coachRouteNl(match.route),note:'Controleer de interne contactdirectory vóór gebruik.',action:'Vrijwillig contact'};
  if(lang==='fr')return{title:'Liv propose cette voie',contact:coachContactFr(match.contact),route:coachRouteFr(match.route),note:'Vérifiez l’annuaire interne avant utilisation.',action:'Contact volontaire'};
  if(lang==='de')return{title:'Liv schlägt diesen Weg vor',contact:coachContactDe(match.contact),route:coachRouteDe(match.route),note:'Prüfen Sie vor Verwendung das interne Kontaktverzeichnis.',action:'Freiwilliger Kontakt'};
  return{title:'Liv suggests this route',contact:match.contact,route:match.route,note:'Verify the internal contact directory before use.',action:'Voluntary contact'};
}
function coachContactNl(s){return s.replace('Project sponsor or PMO','Projectsponsor of PMO').replace('Line manager or confidential contact','Leidinggevende of vertrouwenspersoon').replace('Privacy or Information Security team','Privacy- of Information Security-team').replace('Confidential contact or external prevention service','Vertrouwenspersoon of externe preventiedienst').replace('IT Service Desk','IT Service Desk').replace('People / HR team','People / HR-team').replace('Line manager or internal service desk','Leidinggevende of interne servicedesk')}
function coachContactFr(s){return s.replace('Project sponsor or PMO','Sponsor du projet ou PMO').replace('Line manager or confidential contact','Responsable hiérarchique ou personne de confiance').replace('Privacy or Information Security team','Équipe Privacy ou Sécurité de l’information').replace('Confidential contact or external prevention service','Personne de confiance ou service externe de prévention').replace('IT Service Desk','Service Desk IT').replace('People / HR team','Équipe People / RH').replace('Line manager or internal service desk','Responsable ou service desk interne')}
function coachContactDe(s){return s.replace('Project sponsor or PMO','Projektsponsor oder PMO').replace('Line manager or confidential contact','Führungskraft oder Vertrauensperson').replace('Privacy or Information Security team','Datenschutz- oder Informationssicherheitsteam').replace('Confidential contact or external prevention service','Vertrauensperson oder externer Präventionsdienst').replace('IT Service Desk','IT Service Desk').replace('People / HR team','People-/HR-Team').replace('Line manager or internal service desk','Führungskraft oder interner Service Desk')}
function coachRouteNl(s){if(s.includes('scope'))return'Bespreek scope, prioriteiten, capaciteit en deadline met de projecteigenaar vóór je extra middelen vraagt.';if(s.includes('factual'))return'Begin met een feitelijk overzicht van wat er gebeurde en welk resultaat je nodig hebt. Kies voor een gevoelige relatiekwestie een privégesprek.';if(s.includes('minimum'))return'Deel alleen de minimale context die nodig is en verstuur geen gevoelige gegevens via een open kanaal.';if(s.includes('trust'))return'Kies de contactpersoon die je vertrouwt. Een aanvraag moet vrijwillig zijn en alleen bevatten wat je zelf wilt delen.';if(s.includes('system'))return'Vermeld het betrokken systeem, de impact en eventuele foutmelding, maar deel nooit een wachtwoord.';if(s.includes('HR service'))return'Gebruik het HR-servicekanaal voor beleids- of arbeidsvragen. Een persoonlijke situatie bespreek je beter privé.';return'Verduidelijk de vraag, het gewenste resultaat en de urgentie en kies daarna de dienst met de juiste verantwoordelijkheid.'}
function coachRouteFr(s){if(s.includes('scope'))return'Revoyez le périmètre, les priorités, la capacité et le délai avec le responsable du projet avant de demander des ressources supplémentaires.';if(s.includes('factual'))return'Commencez par un aperçu factuel de ce qui s’est passé et du résultat attendu. Pour une question relationnelle sensible, privilégiez un échange privé.';if(s.includes('minimum'))return'Partagez uniquement le contexte minimum nécessaire et n’envoyez pas de données sensibles par un canal ouvert.';if(s.includes('trust'))return'Choisissez le contact en qui vous avez confiance. La demande doit être volontaire et ne contenir que ce que vous souhaitez partager.';if(s.includes('system'))return'Indiquez le système concerné, l’impact et le message d’erreur, mais ne partagez jamais de mot de passe.';if(s.includes('HR service'))return'Utilisez le canal RH pour les questions de politique ou d’emploi. Un cas personnel se traite mieux en privé.';return'Clarifiez la question, le résultat attendu et l’urgence, puis choisissez le service compétent.'}
function coachRouteDe(s){if(s.includes('scope'))return'Prüfen Sie Umfang, Prioritäten, Kapazität und Termin mit der Projektverantwortung, bevor Sie zusätzliche Ressourcen anfordern.';if(s.includes('factual'))return'Beginnen Sie mit einer sachlichen Übersicht und dem gewünschten Ergebnis. Bei sensiblen Beziehungsfragen ist ein privates Gespräch sinnvoll.';if(s.includes('minimum'))return'Teilen Sie nur den notwendigen Mindestkontext und senden Sie keine sensiblen Daten über einen offenen Kanal.';if(s.includes('trust'))return'Wählen Sie die Person, der Sie vertrauen. Die Anfrage sollte freiwillig sein und nur Angaben enthalten, die Sie teilen möchten.';if(s.includes('system'))return'Nennen Sie das betroffene System, die Auswirkung und eine Fehlermeldung, aber niemals ein Passwort.';if(s.includes('HR service'))return'Nutzen Sie den HR-Servicekanal für Richtlinien- oder Beschäftigungsfragen. Persönliche Fälle sollten privat behandelt werden.';return'Klären Sie Frage, gewünschtes Ergebnis und Dringlichkeit und wählen Sie anschließend die zuständige Stelle.'}

function populateDepartmentFilter(){const sel=$('#departmentFilter'),old=sel.value;sel.innerHTML=`<option value="">${escapeHtml(t('allDepartments'))}</option>`+[...new Set(state.personas.map(p=>p.department))].sort().map(d=>`<option>${escapeHtml(d)}</option>`).join('');sel.value=old}
function renderProfiles(){
  if(!state.personas.length)return;
  populateDepartmentFilter();const q=$('#profileSearch').value.toLowerCase(),dept=$('#departmentFilter').value;
  const filtered=state.personas.filter(p=>(!dept||p.department===dept)&&(!q||`${p.name} ${p.role} ${p.department} ${p.email}`.toLowerCase().includes(q)));
  $('#personaGrid').innerHTML=filtered.length?filtered.map(personaCardHtml).join(''):`<div class="card" style="padding:25px">${escapeHtml(t('noResults'))}</div>`;
}
function personaCardHtml(p){const d=dominant(p)[0];return `<article class="persona-card"><div class="persona-head"><div><strong>${escapeHtml(p.name)}</strong><small>${escapeHtml(p.role)}</small></div><span class="dominant-badge ${ENERGY[d].css}">${ENERGY[d].label}</span></div>${barsHtml(p)}<div class="persona-meta"><span>${escapeHtml(p.department)}</span><span>${escapeHtml((p.language||'en').toUpperCase())}</span></div></article>`}
function updateStats(){
  $('#profileCount').textContent=state.personas.length;$('#departmentCount').textContent=new Set(state.personas.map(p=>p.department)).size;
  let total=0,count=0;for(let i=0;i<state.personas.length;i+=5){for(let j=i+1;j<state.personas.length;j+=11){total+=profileDistance(state.personas[i],state.personas[j]);count++}}
  $('#averageDistance').textContent=`${Math.round(total/Math.max(count,1))}%`;
}
async function importCsv(e){const file=e.target.files?.[0];if(!file)return;const text=await file.text(),parsed=parseAndValidateCsv(text);if(!parsed.ok){toast(t('csvInvalid'));e.target.value='';return}state.personas=parsed.rows;localStorage.setItem('benice.personasCsv',rowsToCsv(parsed.rows));renderProfileSelectors();populateDepartmentFilter();renderProfiles();updateStats();updateSelectedProfiles();toast(t('csvLoaded'));e.target.value=''}
function downloadCurrentCsv(){const blob=new Blob([rowsToCsv(state.personas)],{type:'text/csv;charset=utf-8'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download='benice-personas.csv';a.click();setTimeout(()=>URL.revokeObjectURL(url),500)}
function resetDemoCsv(){localStorage.removeItem('benice.personasCsv');const parsed=parseAndValidateCsv(state.defaultCsv);state.personas=parsed.rows;renderProfileSelectors();populateDepartmentFilter();renderProfiles();updateStats();updateSelectedProfiles();toast(t('demoReset'))}

function groupBy(arr,fn){return arr.reduce((o,x)=>{const k=fn(x);(o[k]??=[]).push(x);return o},{})}
function escapeHtml(s){return String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}
async function copyText(text){if(!text)return;try{await navigator.clipboard.writeText(text);toast(t('copied'))}catch{const ta=document.createElement('textarea');ta.value=text;document.body.appendChild(ta);ta.select();document.execCommand('copy');ta.remove();toast(t('copied'))}}
let toastTimer;function toast(message){clearTimeout(toastTimer);$('#toast').textContent=message;$('#toast').classList.add('show');toastTimer=setTimeout(()=>$('#toast').classList.remove('show'),2600)}
function registerServiceWorker(){if('serviceWorker'in navigator)navigator.serviceWorker.register('./service-worker.js').catch(()=>{})}

init().catch(err=>{console.error(err);toast('BeNice could not start. Run it through a local web server.')});
